local G = DYCLegendary local require = G.DYCModRequire local dlc = G.dlc local spells = require( "dyc_spells" ) local Round = function(num) return math.floor(num + 0.5) end local Clamp = function(num, min, max) return math.min(math.max(num, min), max) end local assets = {Asset( "ATLAS" , "images/inventoryimages/dyclightningstaff.xml" ), Asset( "IMAGE" , "images/inventoryimages/dyclightningstaff.tex" ), Asset( "ANIM" , "anim/dyc_staffs.zip" ), Asset( "ANIM" , "anim/dyc_swap_staffs.zip" ),} local function TableContains(_table, _thing) for k, v in pairs(_table) do if v == _thing then return true end end return false end local function CastTest(staff, caster, target, pos) local finiteuses = staff.components.finiteuses if finiteuses and finiteuses:GetUses() <= 0x0 then return false end return true end local function dyc() local onequip = function(inst, owner) owner.AnimState:OverrideSymbol( "swap_object" , "swap_staffs" , "yellowstaff" ) owner.AnimState:Show( "ARM_carry" ) owner.AnimState:Hide( "ARM_normal" ) end local onunequip = function(inst, owner) owner.AnimState:ClearOverrideSymbol( "swap_object" ) owner.AnimState:Hide( "ARM_carry" ) owner.AnimState:Show( "ARM_normal" ) end local inst = CreateEntity() local trans = inst.entity:AddTransform() local anim = inst.entity:AddAnimState() local sound = inst.entity:AddSoundEmitter() MakeInventoryPhysics(inst) if dlc >= 0x2 then MakeInventoryFloatable(inst, "yellowstaff_water" , "yellowstaff" ) end anim:SetBank( "staffs" ) anim:SetBuild( "staffs" ) anim:PlayAnimation( "yellowstaff" ) inst:AddComponent( "inspectable" ) inst:AddComponent( "inventoryitem" ) inst:AddComponent( "equippable" ) inst.components.equippable:SetOnEquip(onequip) inst.components.equippable:SetOnUnequip(onunequip) return inst end local function OnAttack_Lightning(inst, attacker, target) attacker.SoundEmitter:PlaySound( "dontstarve_DLC001/creatures/lightninggoat/shocked_electric" ) end local function OnProjectileLaunch(inst, attacker, target) inst:DoTaskInTime(0x0, function() local finiteuses = inst.components.finiteuses local uses = finiteuses and finiteuses:GetUses() if finiteuses and uses > 0x0 then local use = inst.components.weapon:GetProjectileCount() / 0x8 local current = finiteuses.current or 0x0 finiteuses:Use(math.min(use, current)) end end) end local function OnStateChange(inst) local finiteuses = inst.components.finiteuses local uses = finiteuses and finiteuses:GetUses() local q = inst:GetQuality() if uses and uses <= 0x0 then inst.components.weapon:SetMultiProjectile({{prefab = "dyc_projectile_lightning" , bezier = {h = 1.2, angle = 0x5a,},},}) inst.components.weapon:SetDamage(inst.damage_UseUp) elseif uses and uses > 0x0 then local number = Clamp(Round((q - 0x1) * 0x4 * 1.5 + 3.5), 0x1, 0x7) local projectiles = {} for i = 0x1, number do local mid = number % 0x2 == 0x1 and (number + 0x1) / 0x2 or number / 0x2 + 0.5 local angle = (i - mid) * 0x19 + 0x5a local delay = (i - 0x1) * 0.08 table.insert(projectiles, {prefab = "dyc_projectile_lightning" , bezier = {h = 1.8, angle = angle,}, delay = delay,}) end inst.components.weapon:SetMultiProjectile(projectiles) inst.components.weapon:SetDamage(inst.damage_Attack) end local damage = inst.damage_Spell * q local spell = inst.dycSpellClusterZaps spell:SetData({caster = spell.caster, damage = damage, aoe = inst.spell_AoeRange, interval = 0.125, speed = 0x26, damageType = "ice" , weapon = inst,}) end local function OnFinished(inst) inst.SoundEmitter:PlaySound( "dontstarve/common/gem_shatter" ) OnStateChange(inst) end local function lightning() local inst = dyc() local anim = inst.AnimState anim:SetBank( "dyc_staffs" ) anim:SetBuild( "dyc_staffs" ) anim:PlayAnimation( "lightningstaff" ) inst.swap_build = "dyc_swap_staffs" inst.swap_symbol = "lightningstaff" local onequip = function(inst, owner) owner.AnimState:OverrideSymbol( "swap_object" , inst.swap_build, inst.swap_symbol) owner.AnimState:Show( "ARM_carry" ) owner.AnimState:Hide( "ARM_normal" ) end inst.components.equippable:SetOnEquip(onequip) if dlc >= 0x2 then MakeInventoryFloatable(inst, "lightningstaff_water" , "lightningstaff" ) end inst.castsound = "dontstarve/common/staffteleport" inst.damage_Spell = 0x14 inst.damage_UseUp = 0x8 inst.damage_Attack = 0xc inst.spell_AoeRange = 0x4 inst:AddComponent( "spellcaster" ) local spell = spells:GetSpell( "clusterzaps" )() inst.dycSpellClusterZaps = spell inst.components.spellcaster:SetSpellFn(function(inst, target, pos) local owner = inst.components.inventoryitem and inst.components.inventoryitem.owner if owner then spell.caster = owner spell:Cast(target, pos) local finiteuses = inst.components.finiteuses if finiteuses then local current = finiteuses.current or 0x0 finiteuses:Use(math.min(0x8, current)) end end end) inst.components.spellcaster:SetOnChannelEndFn(function(inst, caster, target, pos) spell:StopTask() end) inst.components.spellcaster:SetSpellTestFn(CastTest) inst.components.spellcaster.canuseontargets = true inst.components.spellcaster.canuseonpoint = true inst.components.spellcaster.canusefrominventory = false inst.components.spellcaster:InitCooldown(0xa) inst.components.spellcaster:SetCastFXPrefab( "dyc_fx_channelcircle" ) inst.components.spellcaster:SetAOEUI(inst.spell_AoeRange) inst.castfast = true inst.components.inventoryitem.atlasname = "images/inventoryimages/dyclightningstaff.xml" inst.components.inventoryitem.imagename = "dyclightningstaff" inst:AddComponent( "weapon" ) inst.components.weapon:SetDamage(0xa) inst.components.weapon:SetRange(0xf, 0x1e) inst.components.weapon.attackwear = 0x0 inst.components.weapon:SetOnAttack(OnAttack_Lightning) inst.components.weapon:SetOnProjectileLaunch(OnProjectileLaunch) inst.components.weapon:SetProjectile( "dyc_projectile_lightning" ) inst.components.equippable:SetFollowingFXs({{prefab = "dyc_p_lightningstaff_discharge" , follow = "swap_object" , scale = 1.0, x = 0x28, y = - 0x96, z = 0x0,},}) inst:AddComponent( "finiteuses" ) inst.components.finiteuses:SetMaxUses(0x96) inst.components.finiteuses:SetUses(0x96) inst.components.finiteuses:SetOnFinished(OnFinished) inst:ListenForEvent( "percentusedchange" , function() local finiteuses = inst.components.finiteuses local uses = finiteuses and finiteuses:GetUses() if uses and inst.dycLastUses and inst.dycLastUses <= 0x0 and uses > 0x0 then OnStateChange(inst) end inst.dycLastUses = uses end) inst:AddComponent( "repairable" ) inst.components.repairable.repairmaterial = "gem" inst.components.repairable.announcecanfix = false inst.components.repairable.onrepaired = function() OnStateChange(inst) end inst:AddTag( "nopunch" ) inst:AddTag( "dyc_gem_purple" ) inst.scrapProduct = "dyc_gem_purple" inst.OnQualityChange = function(inst, q) OnStateChange(inst) end inst.OnEnchantmentChange = function(inst) OnStateChange(inst) end inst:SetRandomQuality() inst:AddEnchantment( "lightningstaff" ) inst.fxcolor = {0x0, 0.5, 0x1} return inst end return Prefab( "common/inventory/dyc_lstaff" , lightning, assets) 